@startuml
!option handwritten true

note "Please use '!option handwritten true' to enable handwritten" as N1

abstract class Container {
  +__contains__(item)
}

abstract class Iterable {
  +__iter__()
}

abstract class Sized {
  +__len__(item)
}

abstract class Collection {
}

abstract class Mapping {
  +__getitem__(key)
  +keys()
  +items()
  +values()
  +get(key, default)
}

abstract class MutableMapping {
  +__setitem__(key, value)
  +__delitem__(key)
}

class dict {
}

Collection --|> Container
Collection --|> Iterable
Collection --|> Sized
Mapping --|> Collection
MutableMapping --|> Mapping
dict --|> MutableMapping

@enduml
